```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>

int main() {
    int fd[2];
    pipe(fd);

    pid_t pid = fork();

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid == 0) {
        // Child process
        close(fd[1]); // Close write end in child
        dup2(fd[0], STDIN_FILENO); // Redirect child's stdin to the read end of the pipe
        dup2(fd[0], STDOUT_FILENO); // Redirect child's stdout to the read end of the pipe

        close(fd[0]); // Close the read end
        execlp("/bin/echo", "echo", "Hello, World!", (char*)0);
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else {
        // Parent process
        close(fd[0]); // Close read end in parent
        write(fd[1], "Input to child process", 26); // Write data to the write end of the pipe

        close(fd[1]); // Close the write end
        wait(NULL); // Wait for the child to finish
    }

    return 0;
}
```

This code creates a pipe, forks a child process, and then connects the read end of the pipe to both the child's standard input and output. The parent process writes a message to the pipe, which the child reads and prints.
